use std::collections::HashMap;

type OpFn = Box<dyn Fn(f64, f64) -> Result<f64, String>>;

pub struct Calculator {
    ops: HashMap<String, OpFn>,
}

impl Calculator {
    pub fn new() -> Self {
        let mut calc = Calculator { ops: HashMap::new() };
        calc.register("+", |a, b| Ok(a + b));
        calc.register("-", |a, b| Ok(a - b));
        calc.register("*", |a, b| Ok(a * b));
        calc.register("/", |a, b| {
            if b == 0.0 { return Err("division by zero".to_string()); }
            Ok(a / b)
        });
        calc.register("**", |a, b| Ok(a.powf(b)));
        calc.register("%", |a, b| {
            if b == 0.0 { return Err("modulo by zero".to_string()); }
            Ok(a % b)
        });
        calc.register("min", |a, b| Ok(a.min(b)));
        calc.register("max", |a, b| Ok(a.max(b)));
        calc
    }

    pub fn register(&mut self, op: &str, f: impl Fn(f64, f64) -> Result<f64, String> + 'static) {
        self.ops.insert(op.to_string(), Box::new(f));
    }

    pub fn evaluate(&self, op: &str, a: f64, b: f64) -> Result<f64, String> {
        match self.ops.get(op) {
            Some(f) => f(a, b),
            None => Err(format!("unknown operator: {}", op)),
        }
    }
}

// Backward-compatible free function
pub fn evaluate(op: &str, a: f64, b: f64) -> Result<f64, String> {
    Calculator::new().evaluate(op, a, b)
}
